  'Find customers faster than manual outbound.': { ru: 'Находите клиентов быстрее, чем вручную.', es: 'Encuentra clientes más rápido que con outbound manual.', 'en-US': 'Find customers faster than manual outbound.', fr: 'Trouvez des clients plus vite qu’en outbound manuel.', it: 'Trova clienti più velocemente dell’outbound manuale.', pl: 'Znajduj klientów szybciej niż ręcznym outboundem.' },
  'Start with a target market. OutreachAI prepares leads, research, emails and campaign review from one workspace.': { ru: 'Начните с целевого рынка. OutreachAI подготовит лиды, исследование, письма и проверку кампании в одном пространстве.', es: 'Empieza con un mercado objetivo. OutreachAI prepara leads, investigación, emails y revisión de campaña en un workspace.', 'en-US': 'Start with a target market. OutreachAI prepares leads, research, emails and campaign review from one workspace.', fr: 'Commencez par un marché cible. OutreachAI prépare leads, analyse, emails et validation de campagne dans un seul espace.', it: 'Inizia da un mercato target. OutreachAI prepara lead, ricerca, email e revisione campagna in un workspace.', pl: 'Zacznij od rynku docelowego. OutreachAI przygotuje leady, research, emaile i przegląd kampanii w jednym workspace.' },
  'Lead generation, AI research, outbound campaigns and CRM in one workspace.': { ru: 'Поиск лидов, AI-исследование, outbound-кампании и CRM в одном пространстве.', es: 'Generación de leads, investigación IA, campañas outbound y CRM en un workspace.', 'en-US': 'Lead generation, AI research, outbound campaigns and CRM in one workspace.', fr: 'Génération de leads, recherche IA, campagnes outbound et CRM dans un seul espace.', it: 'Lead generation, ricerca AI, campagne outbound e CRM in un workspace.', pl: 'Generowanie leadów, research AI, kampanie outbound i CRM w jednym workspace.' },
  'AI summary': { ru: 'AI резюме', es: 'Resumen IA', 'en-US': 'AI summary', fr: 'Résumé IA', it: 'Riepilogo IA', pl: 'Podsumowanie AI' },
