  'Sign out and create a new account': { ru: 'Выйти и создать новый аккаунт', es: 'Cerrar sesión y crear otra cuenta', 'en-US': 'Sign out and create a new account', fr: 'Se déconnecter et créer un nouveau compte', it: 'Esci e crea un nuovo account', pl: 'Wyloguj się i utwórz nowe konto' },
