  'Save sending setup': { ru: 'Сохранить отправку', es: 'Guardar envío', 'en-US': 'Save sending setup', fr: 'Enregistrer l’envoi', it: 'Salva invio', pl: 'Zapisz wysyłkę' },
  'Saving...': { ru: 'Сохраняем...', es: 'Guardando...', 'en-US': 'Saving...', fr: 'Enregistrement...', it: 'Salvataggio...', pl: 'Zapisywanie...' },
  'Sending setup saved': { ru: 'Настройки отправки сохранены', es: 'Configuración de envío guardada', 'en-US': 'Sending setup saved', fr: 'Configuration d’envoi enregistrée', it: 'Impostazioni invio salvate', pl: 'Ustawienia wysyłki zapisane' },
  'Email sending setup is temporarily unavailable.': { ru: 'Настройка отправки временно недоступна.', es: 'La configuración de envío no está disponible temporalmente.', 'en-US': 'Email sending setup is temporarily unavailable.', fr: 'La configuration d’envoi est temporairement indisponible.', it: 'La configurazione invio è temporaneamente non disponibile.', pl: 'Konfiguracja wysyłki jest chwilowo niedostępna.' },
  'Sending setup could not be saved.': { ru: 'Не удалось сохранить настройки отправки.', es: 'No se pudo guardar la configuración de envío.', 'en-US': 'Sending setup could not be saved.', fr: 'Impossible d’enregistrer la configuration d’envoi.', it: 'Impossibile salvare le impostazioni invio.', pl: 'Nie udało się zapisać ustawień wysyłki.' },
  'Connect sending before launching campaigns.': { ru: 'Подключите отправку перед запуском кампаний.', es: 'Conecta el envío antes de lanzar campañas.', 'en-US': 'Connect sending before launching campaigns.', fr: 'Connectez l’envoi avant de lancer des campagnes.', it: 'Collega l’invio prima di lanciare campagne.', pl: 'Połącz wysyłkę przed uruchomieniem kampanii.' },
  'Ready to send approved emails.': { ru: 'Можно отправлять подтверждённые письма.', es: 'Listo para enviar emails aprobados.', 'en-US': 'Ready to send approved emails.', fr: 'Prêt à envoyer les emails approuvés.', it: 'Pronto a inviare email approvate.', pl: 'Gotowe do wysyłki zatwierdzonych emaili.' },
  'Email sending is disabled for this workspace.': { ru: 'Отправка писем отключена для этого пространства.', es: 'El envío de emails está desactivado en este workspace.', 'en-US': 'Email sending is disabled for this workspace.', fr: 'L’envoi d’emails est désactivé pour cet espace.', it: 'L’invio email è disattivato per questo workspace.', pl: 'Wysyłka emaili jest wyłączona w tej przestrzeni.' },
  'This mailbox provider still needs secure OAuth or SMTP setup.': { ru: 'Для этого почтового сервиса ещё нужна безопасная настройка OAuth или SMTP.', es: 'Este proveedor de correo aún necesita configuración segura OAuth o SMTP.', 'en-US': 'This mailbox provider still needs secure OAuth or SMTP setup.', fr: 'Ce fournisseur email nécessite encore une configuration OAuth ou SMTP sécurisée.', it: 'Questo provider email richiede ancora configurazione OAuth o SMTP sicura.', pl: 'Ten dostawca poczty wymaga jeszcze bezpiecznej konfiguracji OAuth lub SMTP.' },
