  'Outlook (needs OAuth)': { ru: 'Outlook (нужен OAuth)', es: 'Outlook (requiere OAuth)', 'en-US': 'Outlook (needs OAuth)', fr: 'Outlook (OAuth requis)', it: 'Outlook (richiede OAuth)', pl: 'Outlook (wymaga OAuth)' },
