  'Leave blank to keep current password': { ru: 'Оставьте пустым, чтобы сохранить текущий пароль', es: 'Déjalo vacío para conservar la contraseña actual', 'en-US': 'Leave blank to keep current password', fr: 'Laissez vide pour conserver le mot de passe actuel', it: 'Lascia vuoto per mantenere la password attuale', pl: 'Zostaw puste, aby zachować obecne hasło' },
  'Use TLS': { ru: 'Использовать TLS', es: 'Usar TLS', 'en-US': 'Use TLS', fr: 'Utiliser TLS', it: 'Usa TLS', pl: 'Użyj TLS' },
