  'Promising opportunity': { ru: 'Перспективная возможность', es: 'Oportunidad prometedora', 'en-US': 'Promising opportunity', fr: 'Opportunité prometteuse', it: 'Opportunità promettente', pl: 'Obiecująca szansa' },
