  'No strong signal yet. Run company research first.': { ru: 'Сильных сигналов пока нет. Сначала запустите исследование компании.', es: 'Aún no hay señales fuertes. Ejecuta primero la investigación.', 'en-US': 'No strong signal yet. Run company research first.', fr: 'Pas encore de signal fort. Lancez d’abord l’analyse.', it: 'Nessun segnale forte ancora. Avvia prima la ricerca.', pl: 'Brak silnego sygnału. Najpierw uruchom analizę firmy.' },
  'No major risk for the current stage.': { ru: 'Крупных рисков на текущем этапе нет.', es: 'No hay riesgo importante en esta etapa.', 'en-US': 'No major risk for the current stage.', fr: 'Aucun risque majeur à cette étape.', it: 'Nessun rischio importante in questa fase.', pl: 'Brak dużego ryzyka na tym etapie.' },
  'Website available for personalization': { ru: 'Сайт доступен для персонализации', es: 'Sitio disponible para personalización', 'en-US': 'Website available for personalization', fr: 'Site disponible pour personnalisation', it: 'Sito disponibile per personalizzazione', pl: 'Strona dostępna do personalizacji' },
