  'The company is stored in your CRM.': { ru: 'Компания сохранена в вашей CRM.', es: 'La empresa está guardada en tu CRM.', 'en-US': 'The company is stored in your CRM.', fr: 'L’entreprise est enregistrée dans votre CRM.', it: 'L’azienda è salvata nel CRM.', pl: 'Firma jest zapisana w CRM.' },
  'Lead saved to CRM': { ru: 'Лид сохранён в CRM', es: 'Lead guardado en CRM', 'en-US': 'Lead saved to CRM', fr: 'Lead enregistré dans le CRM', it: 'Lead salvato nel CRM', pl: 'Lead zapisany w CRM' },
  'AI research created the company summary and sales angle.': { ru: 'AI-исследование создало сводку и угол продажи.', es: 'La investigación IA creó resumen y ángulo.', 'en-US': 'AI research created the company summary and sales angle.', fr: 'L’analyse IA a créé le résumé et l’angle.', it: 'La ricerca AI ha creato sintesi e angolo.', pl: 'Analiza AI utworzyła podsumowanie i kąt.' },
