  'Contact discovery ran, but no verified email was available.': { ru: 'Поиск контактов выполнен, но проверенный email недоступен.', es: 'La búsqueda de contactos se ejecutó, pero no había email verificado.', 'en-US': 'Contact discovery ran, but no verified email was available.', fr: 'La recherche de contacts a été exécutée, mais aucun email vérifié n’était disponible.', it: 'La ricerca contatti è stata eseguita, ma nessuna email verificata era disponibile.', pl: 'Wyszukiwanie kontaktów wykonano, ale zweryfikowany email nie był dostępny.' },
  'A decision maker or business contact was added.': { ru: 'Добавлено лицо, принимающее решение, или рабочий контакт.', es: 'Se añadió un decisor o contacto de negocio.', 'en-US': 'A decision maker or business contact was added.', fr: 'Un décideur ou contact métier a été ajouté.', it: 'È stato aggiunto un decision maker o contatto.', pl: 'Dodano osobę decyzyjną lub kontakt.' },
  'A personalized draft was prepared for review.': { ru: 'Персональный черновик подготовлен для проверки.', es: 'Borrador personalizado preparado para revisión.', 'en-US': 'A personalized draft was prepared for review.', fr: 'Brouillon personnalisé prêt à relire.', it: 'Bozza personalizzata pronta per revisione.', pl: 'Spersonalizowany szkic gotowy do przeglądu.' },
  'A user approved the draft before sending.': { ru: 'Пользователь утвердил черновик перед отправкой.', es: 'Un usuario aprobó el borrador antes de enviar.', 'en-US': 'A user approved the draft before sending.', fr: 'Un utilisateur a approuvé le brouillon avant envoi.', it: 'Un utente ha approvato la bozza prima dell’invio.', pl: 'Użytkownik zatwierdził szkic przed wysyłką.' },
  'Approved outreach was sent.': { ru: 'Утверждённое письмо отправлено.', es: 'Outreach aprobado enviado.', 'en-US': 'Approved outreach was sent.', fr: 'L’outreach approuvé a été envoyé.', it: 'Outreach approvato inviato.', pl: 'Zatwierdzona wiadomość wysłana.' },
  'Email not sent yet': { ru: 'Письмо ещё не отправлено', es: 'Email aún no enviado', 'en-US': 'Email not sent yet', fr: 'Email pas encore envoyé', it: 'Email non ancora inviata', pl: 'Email jeszcze nie wysłany' },
