  'Review and approve email': { ru: 'Проверить и утвердить письмо', es: 'Revisar y aprobar email', 'en-US': 'Review and approve email', fr: 'Relire et approuver l’email', it: 'Rivedi e approva email', pl: 'Sprawdź i zatwierdź email' },
  'More actions': { ru: 'Другие действия', es: 'Más acciones', 'en-US': 'More actions', fr: 'Autres actions', it: 'Altre azioni', pl: 'Więcej działań' },
