  'Decision maker saved': { ru: 'Контакт сохранён', es: 'Decisor guardado', 'en-US': 'Decision maker saved', fr: 'Décideur enregistré', it: 'Decision maker salvato', pl: 'Osoba decyzyjna zapisana' },
