  'Needs review': { ru: 'Что проверить', es: 'Qué revisar', 'en-US': 'Needs review', fr: 'À vérifier', it: 'Da verificare', pl: 'Do sprawdzenia' },
  'Best next action': { ru: 'Лучшее следующее действие', es: 'Mejor siguiente acción', 'en-US': 'Best next action', fr: 'Meilleure prochaine action', it: 'Migliore prossima azione', pl: 'Najlepszy następny krok' },
  'What to do next': { ru: 'Что сделать дальше', es: 'Qué hacer ahora', 'en-US': 'What to do next', fr: 'Que faire ensuite', it: 'Cosa fare dopo', pl: 'Co zrobić dalej' },
