  'Email draft checked': { ru: 'Черновик письма проверен', es: 'Borrador de email revisado', 'en-US': 'Email draft checked', fr: 'Brouillon email vérifié', it: 'Bozza email verificata', pl: 'Szkic emaila sprawdzony' },
