export function isLocale(value: string | null | undefined): value is Locale {
  return Boolean(value && locales.includes(value as Locale));
}

export function translate(key: TranslationKey | string, locale: Locale): string {
  const localized = translations[locale]?.[key as TranslationKey];
  if (localized) return localized;
  const phrase = visiblePhraseTranslations[key]?.[locale];
  if (phrase) return phrase;
  if (locale === 'en') {
    const americanEnglishPhrase = visiblePhraseTranslations[key]?.['en-US'];
    if (americanEnglishPhrase) return americanEnglishPhrase;
  }
  return en[key as TranslationKey] || key;
}

export function translateVisibleText(text: string, locale: Locale): string {
  const trimmed = text.trim();
  if (!trimmed) return text;
  const phrase = visiblePhraseTranslations[trimmed]?.[locale];
  if (phrase) return text.replace(trimmed, phrase);
  const englishEntry = Object.entries(en).find(([, value]) => value === trimmed);
  const localizedEntry = englishEntry || Object.values(translations)
    .flatMap((map) => Object.entries(map))
    .find(([, value]) => value === trimmed);
  if (localizedEntry) {
    const translated = translate(localizedEntry[0], locale);
    return text.replace(trimmed, translated);
  }
  if (locale === 'en') {
    const sourcePhrase = Object.entries(visiblePhraseTranslations).find(([, values]) => Object.values(values).includes(trimmed));
    return sourcePhrase ? text.replace(trimmed, sourcePhrase[0]) : text;
  }
  let translatedText = text;
  for (const [source, values] of Object.entries(visiblePhraseTranslations).sort(([a], [b]) => b.length - a.length)) {
    const translated = values[locale];
    if (translated && translatedText.includes(source)) translatedText = translatedText.replaceAll(source, translated);
  }
  return translatedText;
}
